def cached_response(ttl: int | None = None, key_prefix: str = ""):
    """
    Decorator to cache Flask route responses.

    Args:
        ttl: Time-to-live in seconds (None uses default).
        key_prefix: Optional prefix for cache keys.
    """
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            cache_key = _build_cache_key(key_prefix or f.__name__, request)

            cached_data = cache.get(cache_key)
            if cached_data is not None:
                response = jsonify(cached_data)
                response.headers["X-Cache"] = "HIT"
                return response

            result = f(*args, **kwargs)

            if isinstance(result, tuple):
                data, status_code = result[0], result[1] if len(result) > 1 else 200
            else:
                data = result
                status_code = 200

            if isinstance(data, dict) and 200 <= status_code < 300:
                try:
                    cache.set(cache_key, data, ttl=ttl)
                except CacheSerializationError:
                    pass

            response = jsonify(data)
            response.status_code = status_code
            response.headers["X-Cache"] = "MISS"
            return response

        return wrapper
    return decorator


def _build_cache_key(prefix: str, req) -> str:
    """Build a deterministic cache key from the request."""
    parts = [
        prefix,
        req.method,
        req.path,
        str(sorted(req.args.items())),
    ]
    return "|".join(parts)


